REPLACE:
    var relatedMinRelevance int
    rootCmd.PersistentFlags().IntVar(&relatedMinRelevance, "related-min-relevance", 20,
        "Minimum relevance score (0-100) for related work (default 20)")

WITH a custom pflag.Value that accepts both forms:

    type relevanceFlag struct{ pct int }   // canonical: 0..100

    func (r *relevanceFlag) String() string { return strconv.Itoa(r.pct) }
    func (r *relevanceFlag) Type() string   { return "int|float" }
    func (r *relevanceFlag) Set(s string) error {
        s = strings.TrimSpace(s)
        if s == "" {
            return fmt.Errorf("--related-min-relevance: empty value; expected integer 0-100 (e.g. 20) or float 0.0-1.0 (e.g. 0.20)")
        }
        // Try integer percent first.
        if !strings.ContainsAny(s, ".eE") {
            n, err := strconv.Atoi(s)
            if err != nil {
                return fmt.Errorf("--related-min-relevance: invalid value %q; expected integer 0-100 (e.g. 20) or float 0.0-1.0 (e.g. 0.20)", s)
            }
            if n < 0 || n > 100 {
                return fmt.Errorf("--related-min-relevance: %d out of range; integer form must be 0-100 (got %d). Tip: --relations-threshold uses float 0.0-1.0; this flag uses int 0-100 OR equivalent float.", n, n)
            }
            r.pct = n
            return nil
        }
        // Float form: 0.0-1.0 fraction.
        f, err := strconv.ParseFloat(s, 64)
        if err != nil {
            return fmt.Errorf("--related-min-relevance: invalid value %q; expected integer 0-100 (e.g. 20) or float 0.0-1.0 (e.g. 0.20)", s)
        }
        if f < 0.0 || f > 1.0 {
            return fmt.Errorf("--related-min-relevance: float %g out of range; float form must be 0.0-1.0 (try %d for the integer form)", f, int(f))
        }
        r.pct = int(math.Round(f * 100))
        return nil
    }

    var relatedMinRelevance relevanceFlag
    rootCmd.PersistentFlags().Var(&relatedMinRelevance, "related-min-relevance",
        "Minimum relevance for related work. Accepts int 0-100 (default 20) OR float 0.0-1.0 (e.g. 0.20). Sibling --relations-threshold uses float-only.")

Downstream readers use relatedMinRelevance.pct (still 0..100 internally). Help text now teaches both units AND points at the sibling flag, eliminating the cross-flag unit confusion.

