Pseudocode:
fn handle_unknown_flag(flag: &str, known: &[&str]) -> Error {
    let close = known.iter()
        .filter(|k| levenshtein(flag, k) == 1)
        .min_by_key(|k| k.len());
    if let Some(suggestion) = close {
        eprintln!("error: unknown flag '''--{}'''; did you mean '''--{}'''?", flag, suggestion);
        eprintln!("  hint: see '''bv --robot-help''' for the agent-mode flag inventory");
        return Error::UnknownFlagDidYouMean { typed: flag.into(), suggested: suggestion.to_string() };
    }
    eprintln!("error: unknown flag '''--{}'''", flag);
    Error::UnknownFlag(flag.into())
}

