In the bv argument parser (clap-based, root command), wire a flag-error hook that runs when clap surfaces UnknownArgument. Build the candidate set from clap'\''s own metadata (introspect Command::get_arguments() for long/short names, including the robot-* family: --robot-triage, --robot-help, --robot-docs, --robot-schema, --help, --json, --yes, -f/--format) at startup so the list never drifts. Compute Levenshtein distance between the typed flag (with leading dashes stripped) and each candidate; if the minimum distance is exactly 1, print a single additive line to stderr before exiting non-zero. Pseudocode:

fn handle_unknown_flag(typed: &str, cmd: &clap::Command) -> ! {
    let known: Vec<String> = cmd.get_arguments()
        .filter_map(|a| a.get_long().map(|s| s.to_string()))
        .collect();
    let stripped = typed.trim_start_matches('-');
    let suggestion = known.iter()
        .map(|k| (k, levenshtein(stripped, k)))
        .filter(|(_, d)| *d == 1)
        .min_by_key(|(_, d)| *d)
        .map(|(k, _)| k.clone());
    if let Some(s) = suggestion {
        eprintln!("error: unknown flag '\''{}'\''; did you mean '\''--{}'\''?", typed, s);
        eprintln!("  see '\''bv --help'\'' for the full flag list, or '\''bv --robot-help'\'' for the agent interface.");
    } else {
        eprintln!("error: unknown flag '\''{}'\''. run '\''bv --help'\'' to see available flags.", typed);
    }
    std::process::exit(2);
}

